import React, { useState, useEffect } from 'react';
import AOS from 'aos';
import 'aos/dist/aos.css';

// Component Imports
import Hero from './components/sections/Hero';
import FlowerPetals from './components/animations/FlowerPetals';
import Timeline from './components/sections/Timeline';
import Gallery from './components/sections/Gallery';
import RSVPForm from './components/sections/RSVPForm';
import InvitationQR from './components/ui/InvitationQR';
import MusicPlayer from './components/ui/MusicPlayer';
import Navbar from './components/ui/Navbar';
import ThreeRings from './components/animations/ThreeRings';
import Profiles from './components/sections/Profiles';
import VenueMap from './components/ui/VenueMap';
import Events from './components/sections/Events';
import GiftRegistry from './components/sections/GiftRegistry';
import Guestbook from './components/ui/Guestbook';
import ParallaxSection from './components/animations/ParallaxSection';
import GlassCountdown from './components/ui/GlassCountdown';
import FloatingActions from './components/ui/FloatingActions';
import StyleGuide from './components/sections/StyleGuide';
import LiveCounter from './components/ui/LiveCounter';
import SuccessModal from './components/ui/SuccessModal';
import Itinerary from './components/sections/Itinerary';
import Squad from './components/sections/Squad';

function App() {
  const [submittedData, setSubmittedData] = useState(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Handle successful RSVP submission
  const handleRSVPSuccess = (data) => {
    setSubmittedData(data);
    setIsModalOpen(true); 
  };

  useEffect(() => {
    try {
      AOS.init({ 
        duration: 1000, 
        once: true,
        offset: 50,
        disable: window.innerWidth < 768 
      });
      AOS.refresh();
    } catch (e) {
      console.error("AOS init error:", e);
    }
  }, []);

  return (
    <div className="bg-[#FAF9F6] min-h-screen relative selection:bg-luxury-gold selection:text-white">
      {/* --- Global Floating UI Elements --- */}
      <Navbar />
      <MusicPlayer />
      <FlowerPetals />
      <FloatingActions />
      
      {/* --- Success Pop-up Modal --- */}
      <SuccessModal 
        isOpen={isModalOpen} 
        guestName={submittedData?.name} 
        onClose={() => setIsModalOpen(false)} 
      />

      {/* 1. Cinematic Hero Section */}
      <section id="home" className="relative h-screen flex flex-col items-center justify-center overflow-hidden">
        <div className="absolute inset-0 z-0">
          <ThreeRings />
        </div>
        <div className="text-center z-10 space-y-8">
          <h1 className="text-6xl md:text-9xl font-serif text-luxury-gold italic drop-shadow-sm" data-aos="zoom-in">
            Prabha & Empty
          </h1>
          <div data-aos="fade-up" data-aos-delay="400">
            <GlassCountdown targetDate="2026-12-04" />
          </div>
          <p className="text-luxury-dark tracking-[0.6em] uppercase text-[10px] md:text-xs mt-6 opacity-70" data-aos="fade-up" data-aos-delay="600">
            Inviting You To Celebrate Our Union
          </p>
        </div>
      </section>

      {/* 2. Couple Profiles */}
      <Profiles />

      {/* 3. Visual Break: Parallax Quote */}
      <ParallaxSection />

      {/* 4. Wedding Itinerary (Detailed Schedule) */}
      <Itinerary />

      {/* 5. Love Story Timeline */}
      <section id="story" className="py-24 max-w-5xl mx-auto px-6">
        <div className="text-center mb-16" data-aos="fade-up">
          <h2 className="font-serif text-5xl italic text-gray-800">Our Journey</h2>
          <div className="h-px w-24 bg-luxury-gold mx-auto mt-4"></div>
        </div>
        <Timeline />
      </section>

      {/* 6. The Wedding Squad */}
      <Squad />

      {/* 7. Event Highlights (Events component) */}
      <Events />

      {/* 8. Photo Gallery */}
      <section id="gallery" className="py-12 bg-white">
        <Gallery />
      </section>

      {/* 9. Dress Code & Style Guide */}
      <StyleGuide />

      {/* 10. Social Proof: Live Guest Counter */}
      <LiveCounter />

      {/* 11. Guestbook / Wishes Wall */}
      <Guestbook />

      {/* 12. Location & Gift Registry */}
      <VenueMap />
      <GiftRegistry />

      {/* 13. RSVP Section */}
      <section id="rsvp" className="py-24 bg-[#1A1A1B] text-white overflow-hidden">
        <div className="max-w-4xl mx-auto px-6">
          <div className="text-center mb-12" data-aos="fade-up">
            <h2 className="font-serif text-4xl italic text-luxury-gold">Will You Attend?</h2>
            <p className="text-gray-400 text-[10px] uppercase tracking-widest mt-2">Please respond by November 2026</p>
          </div>
          
          <RSVPForm onSubmissionSuccess={handleRSVPSuccess} />

          {/* Fallback Display if Modal is closed but data exists */}
          {submittedData && !isModalOpen && (
            <div className="flex flex-col items-center mt-12" data-aos="zoom-in">
               <h3 className="font-serif text-2xl mb-4 italic">See You Soon, {submittedData.name}!</h3>
               <InvitationQR guestName={submittedData.name} />
            </div>
          )}
        </div>
      </section>

      {/* 14. Footer */}
      <footer className="py-16 text-center bg-[#FAF9F6] border-t border-gray-100">
        <div className="font-serif italic text-3xl text-luxury-dark mb-4">P & E</div>
        <p className="text-gray-400 uppercase tracking-[0.4em] text-[9px]">
          Designed for Prabha & Empty — December 4, 2026
        </p>
        <p className="text-gray-300 text-[8px] mt-4 tracking-widest uppercase">
          Made with Love — 2026
        </p>
      </footer>
    </div>
  );
}
  
export default App;
